import { sanitizeInput } from './utils.js';

/**
 * Manages chat history, message rendering, and API communication.
 */
export class ChatManager {
  constructor(configManager, uiManager) {
    this.configManager = configManager;
    this.uiManager = uiManager;
    this.chatHistory = [];
    this.isProcessing = false;
    // Necessario accesso al ModelManager per il fallback intelligente
    // (Assumiamo che venga passato o accessibile via window.app, ma meglio passarlo nel costruttore se possibile)
    // Per ora lo recuperiamo dall'istanza globale se non iniettato, oppure modifichiamo app.js per passarlo.
    // Hack sicuro per mantenere compatibilità file:
    this.getModelManager = () => window.app ? window.app.modelManager : null;
  }

  loadHistory() {
    const hist = localStorage.getItem('chatHistory');
    if (hist) this.chatHistory = JSON.parse(hist);
  }

  saveHistory() {
    localStorage.setItem('chatHistory', JSON.stringify(this.chatHistory));
  }

  clearChat() {
    this.chatHistory = [];
    this.saveHistory();
    document.getElementById('chat-container').innerHTML = `
            <div class="flex w-full mt-4 justify-center text-xs text-gray-400"><span>Session reset</span></div>`;
  }

  renderChatMessages() {
    const container = document.getElementById('chat-container');
    container.innerHTML = '<div class="flex w-full mt-4 justify-center text-[10px] text-gray-400 uppercase tracking-widest">Inizio Sessione</div>';
    this.chatHistory.forEach(msg => {
      this.appendMessageBubble(msg.role, msg.content, false);
    });
    this.uiManager.scrollToBottom();
  }

  appendMessageBubble(role, content, animate = true) {
    const container = document.getElementById('chat-container');
    const isUser = role === 'user';
    const wrapper = document.createElement('div');
    wrapper.className = `flex w-full ${isUser ? 'justify-end' : 'justify-start'} ${animate ? 'fade-in' : ''}`;

    const config = this.configManager.getConfig();
    const style = isUser ? `background-color: ${config.tenantSettings.primaryColor}; color: white;` : '';
    let htmlContent = isUser ? sanitizeInput(content) : marked.parse(content);

    if (!isUser) {
      htmlContent = DOMPurify.sanitize(htmlContent);
    }

    wrapper.innerHTML = `
            <div class="max-w-[85%] md:max-w-[70%] rounded-2xl px-4 py-3 shadow-sm text-[15px] leading-relaxed prose prose-sm ${isUser ? 'prose-invert' : ''}" style="${style}">${htmlContent}</div>`;
    container.appendChild(wrapper);
    this.uiManager.scrollToBottom();
  }

  handleEnter(e) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      this.sendMessage();
    }
  }

  /**
   * Sends the user message to the AI and handles the response.
   * @param {boolean} [isRetry=false] - Whether this is a rescue/retry attempt.
   * @param {number} [retryIndex=0] - Index for the fallback model pool.
   * @returns {Promise<void>}
   */
  async sendMessage(isRetry = false, retryIndex = 0) {
    if (this.isProcessing && !isRetry) return;

    const inputEl = document.getElementById('user-input');
    let userText = inputEl.value.trim();

    if (isRetry) {
      const lastUserMsg = this.chatHistory.slice().reverse().find(m => m.role === 'user');
      if (lastUserMsg) userText = lastUserMsg.content;
    } else {
      if (!userText) return;

      const config = this.configManager.getConfig();
      if (config.safety.filterEnabled) {
        const textLower = userText.toLowerCase();
        const hasKeyword = config.safety.allowedKeywords.some(k => textLower.includes(k.toLowerCase()));
        if (!hasKeyword && config.safety.allowedKeywords.length > 0) {
          this.uiManager.showToast('Safety Filter Triggered', 'error');
          this.appendMessageBubble('user', userText);
          setTimeout(() => this.appendMessageBubble('assistant', `🚫 ${config.safety.blockMessage}`), 300);
          inputEl.value = '';
          inputEl.style.height = 'auto';
          return;
        }
      }

      this.appendMessageBubble('user', userText);
      this.chatHistory.push({ role: 'user', content: userText });
      this.saveHistory();
      inputEl.value = '';
      inputEl.style.height = 'auto';
    }

    this.isProcessing = true;
    showThinking();
    const btn = document.getElementById('send-btn');
    btn.disabled = true;
    btn.innerHTML = '<div class="loader w-5 h-5 border-t-white border-2"></div>';

    const config = this.configManager.getConfig();
    let systemContent = config.behavior.systemPrompt;
    if (config.knowledgeBase.active && config.knowledgeBase.content.trim() !== '') {
      systemContent += `\n\n[CONTEXT KNOWLEDGE BASE]\n${config.knowledgeBase.content}\n[END CONTEXT]\nUtilizza questo contesto per rispondere se pertinente.`;
    }

    const messagesPayload = [
      { role: 'system', content: systemContent },
      ...this.chatHistory.slice(-10),
    ];

    let creds = this.configManager.getEffectiveCredentials();
    let activeModel = config.apiConfig.model;
    let endpoint = `${config.apiConfig.baseUrl.replace(/\/+$/, '')}/chat/completions`;

    // --- LOGICA SMART FALLBACK ---
    if (isRetry) {
      // Forza l'uso di OpenRouter e della chiave fallback
      const mm = this.getModelManager();
      const fallbackModel = mm ? mm.getFallbackModel(retryIndex) : null;
      
      // Se abbiamo finito i modelli di fallback o non ne abbiamo
      if (!fallbackModel) {
        this.isProcessing = false;
        this.appendMessageBubble('assistant', '⚠️ **Servizio non disponibile:** Nessun modello gratuito ha risposto. Riprova più tardi.');
        btn.disabled = false;
        btn.innerHTML = '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>';
        return;
      }

      // Configurazione per il tentativo di salvataggio
      console.log(`Tentativo Fallback #${retryIndex + 1} con: ${fallbackModel.id}`);
      activeModel = fallbackModel.id;
      creds = { key: this.configManager.getSecureFallback(), isDefault: true };
      endpoint = 'https://openrouter.ai/api/v1/chat/completions'; // Forza endpoint sicuro
    }
    // -----------------------------

    try {
      const headers = { 'Content-Type': 'application/json' };

      if (creds.key) {
        headers['Authorization'] = `Bearer ${creds.key}`;
      }
      // Header specifici OpenRouter
      if (endpoint.includes('openrouter')) {
        headers['HTTP-Referer'] = window.location.href;
        headers['X-Title'] = 'AmuniBot Wrapper';
      }

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({
          model: activeModel,
          messages: messagesPayload,
          temperature: config.behavior.temperature,
          max_tokens: config.behavior.maxTokens || 2048,
        }),
      });

      if (!response.ok) {
        // Intercetta errori recuperabili: 401 (Auth), 402 (Payment), 429 (Rate Limit), 5xx (Server Error)
        if ([401, 402, 429, 500, 502, 503].includes(response.status)) {
             console.warn(`Errore ${response.status} con modello ${activeModel}. Attivazione Fallback...`);
             await this.sendMessage(true, retryIndex + 1); // Ricorsione con indice incrementato
             return;
        }

        const errText = await response.text();
        throw new Error(`Status ${response.status}: ${errText}`);
      }

      const data = await response.json();
      let botResponse = data.choices[0].message.content;

      // Se abbiamo usato un fallback, avvisiamo discretamente l'utente
      if (isRetry) {
        const mm = this.getModelManager();
        const usedModel = mm ? mm.getFallbackModel(retryIndex).name : activeModel;
        botResponse += `\n\n*[Sistema: Generato con modello di backup gratuito (${usedModel})]*`;
      }

      this.chatHistory.push({ role: 'assistant', content: botResponse });
      this.saveHistory();
      this.appendMessageBubble('assistant', botResponse);

    } catch (error) {
      console.error(error);
      // Se è un errore di rete generico (es. offline) proviamo comunque il fallback se non lo abbiamo già fatto troppe volte
      if (!isRetry && retryIndex === 0) {
          this.uiManager.showToast('Errore connessione. Tentativo backup...', 'warning');
          await this.sendMessage(true, 0);
          return;
      }

      let msg = `⚠️ **Errore API:** ${sanitizeInput(error.message)}`;
      this.uiManager.showToast(`Errore: ${error.message}`, 'error');
      this.appendMessageBubble('assistant', msg);
    } finally {
      hideThinking();
      this.isProcessing = false;
      btn.disabled = false;
      btn.innerHTML = '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>';
      document.getElementById('user-input').focus();
    }
  }
