import { ConfigManager } from './config.js';
import { UIManager } from './ui.js';
import { ChatManager } from './chat.js';
import { ModelManager } from './models.js';
import { debounce, readFileAsText, parsePDF } from './utils.js';
import { initTailwind } from './tailwind-config.js';

/**
 * Main Application class that orchestrates the different managers.
 */
class App {
  constructor() {
    this.configManager = new ConfigManager();
    this.uiManager = new UIManager(this.configManager);
    this.chatManager = new ChatManager(this.configManager, this.uiManager);
    this.modelManager = new ModelManager(this.configManager, this.uiManager);
  }

  /**
   * Initializes the application.
   */
  init() {
    initTailwind();
    this.configManager.loadConfig();
    this.chatManager.loadHistory();
    this.configManager.renderConfigValues();
    this.chatManager.renderChatMessages();
    this.uiManager.applyStyles();
    this.uiManager.switchView('admin');

    // Init dynamic UI
    this.modelManager.handleProviderChange(this.configManager.getConfig().apiConfig.provider, false);
    this.modelManager.updateKeyStatusUI();
    this.modelManager.debouncedCheckHealth = debounce(this.modelManager.checkHealth.bind(this.modelManager), 1000);

    // Auto-sync solo se siamo su OpenRouter e non abbiamo modelli
    const config = this.configManager.getConfig();
    if(config.apiConfig.provider === 'openrouter' && !config.apiConfig.model) {
      setTimeout(() => this.modelManager.syncModels(), 500);
    } else {
      this.modelManager.checkHealth();
    }

    this.modelManager.updateContextUsage();

    // Auto-resize textarea
    const tx = document.getElementById('user-input');
    tx.addEventListener('input', function(){
      this.style.height = 'auto';
      this.style.height = (this.scrollHeight) + 'px';
    });
  }

  /**
   * Handles the upload and parsing of a file for the knowledge base.
   * @param {HTMLInputElement} input - The file input element.
   */
  async handleFileUpload(input) {
    if (input.files && input.files[0]) {
      const file = input.files[0];
      const loader = document.getElementById('file-loader');
      loader.classList.remove('hidden');

      try {
        let text = '';
        if (file.type === 'application/pdf') {
          text = await parsePDF(file);
        } else {
          text = await readFileAsText(file);
        }

        const config = this.configManager.getConfig();
        const currentContent = config.knowledgeBase.content;
        const newContent = currentContent
          ? `${currentContent}\n\n--- [FILE: ${file.name}] ---\n${text}`
          : `--- [FILE: ${file.name}] ---\n${text}`;

        this.configManager.updateConfig('knowledgeBase.content', newContent);
        document.getElementById('conf-kb-content').value = newContent;
        this.modelManager.updateContextUsage();
        this.uiManager.showToast(`File caricato: ${file.name}`);

      } catch (error) {
        console.error(error);
        this.uiManager.showToast('Errore caricamento file.', 'error');
      } finally {
        loader.classList.add('hidden');
        input.value = '';
      }
    }
  }

  /**
   * Switches the current active view.
   * @param {string} viewName - The name of the view to switch to.
   */
  switchView(viewName) {
    this.uiManager.switchView(viewName);
  }

  /**
   * Toggles the visibility of the advanced settings modal.
   * @param {boolean} show - Whether to show or hide the modal.
   */
  toggleAdvancedModal(show) {
    this.uiManager.toggleAdvancedModal(show);
  }

  /**
   * Updates a configuration value and applies styles.
   * @param {string} path - The config path.
   * @param {any} value - The new value.
   */
  updateConfig(path, value) {
    this.configManager.updateConfig(path, value);
    this.uiManager.applyStyles();
  }

  /**
   * Handles the change of the AI provider.
   * @param {string} provider - The selected provider.
   */
  handleProviderChange(provider) {
    this.modelManager.handleProviderChange(provider, true);
  }

  /**
   * Updates the safety keywords.
   * @param {string} value - Comma-separated keywords.
   */
  updateKeywords(value) {
    this.configManager.updateKeywords(value);
  }

  /**
   * Clears the chat history.
   */
  clearChat() {
    this.chatManager.clearChat();
  }

  /**
   * Sends a message to the AI.
   * @param {boolean} [isRetry=false] - Whether this is a retry attempt.
   */
  sendMessage(isRetry = false) {
    this.chatManager.sendMessage(isRetry);
  }

  /**
   * Handles the Enter key press in the chat input.
   * @param {KeyboardEvent} event - The keyboard event.
   */
  handleEnter(event) {
    this.chatManager.handleEnter(event);
  }

  /**
   * Synchronizes the available models from the provider.
   */
  syncModels() {
    this.modelManager.syncModels();
  }

  /**
   * Handles the selection of a model.
   * @param {string} value - The model ID.
   */
  handleModelSelect(value) {
    this.modelManager.handleModelSelect(value);
  }

  /**
   * Toggles the custom model input field.
   */
  toggleCustomModelInput() {
    this.modelManager.toggleCustomModelInput();
  }

  /**
   * Returns the debounced health check function.
   * @returns {Function}
   */
  get debouncedCheckHealth() {
    return this.modelManager.debouncedCheckHealth;
  }
}

// Global app instance
const app = new App();

// Initialize immediately since methods are needed for onclick handlers
app.init();

// Export for global access if needed
window.app = app;
